#include <stdio.h>

 int main() {
 	int c;
 	FILE* ulaz = fopen("prva.txt", "r");
 	if (ulaz == NULL) {
 		printf("Otvaranje datoteke prva.txt nije uspjelo");
 		return 1;
 	}
 	FILE* izlaz = fopen("druga.txt", "w");
 	if (izlaz == NULL) {
 		fclose(ulaz);
 		printf("Otvaranje datoteke druga.txt nije uspjelo");
 		return 2;
 	}
 	do {
 		c = fgetc(ulaz);
 		if (c != EOF) fputc (c, izlaz);
 		if (ferror(ulaz) || ferror(izlaz)) {
 			printf("Greska.\n");
 			break;
 		}
 	} while (!feof(ulaz));
 	printf("Kopiranje zavrseno.");
 	fclose (ulaz);
 	fclose (izlaz);
 	return 0;
 }
